export function deriveBlockedRunOutcome(
  blockedRun: RunValue,
  awaitedCompletion: CompletionValue,
): DerivedRunOutcome {
  if (
    blockedRun.state !== "blocked" ||
    blockedRun.blockedOnCompletionId !== awaitedCompletion.completionId
  ) {
    return { kind: "noop" }
  }
  switch (awaitedCompletion.state) {
    case "rejected":
      return { kind: "fail", error: awaitedCompletion.error }
    case "cancelled":
      return { kind: "cancel", terminalReason: awaitedCompletion.terminalReason }
    case "resolved":
    case "pending":
      return { kind: "noop" }
  }
}

export function deriveReadyWork(
  snapshot: ProjectionSnapshot,
): ReadyWorkProjection {
  const readyWork = new Map<string, ReadyWorkItem>()
  for (const run of snapshot.runs.values()) {
    if (run.state !== "blocked") continue
    if (run.blockedOnCompletionId === undefined) continue
    const completion = snapshot.completions.get(run.blockedOnCompletionId)
    if (completion === undefined) continue
    if (completion.state !== "resolved") continue
    readyWork.set(run.runId, {
      runId: run.runId,
      completionId: completion.completionId,
      result: completion.result,
    })
  }
  return { foldVersion: snapshot.foldVersion, readyWork }
}

export function failRun(
  current: RunValue,
  args: { readonly error: unknown },
): ChangeEvent {
  return runUnsafe(failRunEffect(current, args))
}

export function firstValidClaim(
  workId: string,
  attempts: ReadonlyArray<ClaimAttemptValue>,
): ClaimAttemptValue | undefined {
  for (const attempt of attempts) {
    if (attempt.workId !== workId) continue
    return attempt
  }
  return undefined
}

export function foldCompletionRecords(
  completionId: string,
  records: ReadonlyArray<CompletionValue>,
): CompletionValue | undefined {
  return foldFirstValidTerminalWinner(
    records,
    (record) => record.completionId === completionId,
    (record) => isTerminalCompletion(record.state),
  )
}

export function foldRunRecords(
  runId: string,
  records: ReadonlyArray<RunValue>,
): RunValue | undefined {
  return foldFirstValidTerminalWinner(
    records,
    (record) => record.runId === runId,
    (record) => isTerminalRun(record.state),
  )
}

