(
  value: unknown,
): value is EventStreamStateRow => {
  if (
    typeof value !== "object" ||
    value === null ||
    !("headers" in value)
  ) {
    return false
  }
  if (!isChangeEvent(value as never)) return false
  const row = value as UnknownChangeEvent
  return (
    row.type === EVENT_STREAM_ROW_TYPE &&
    row.headers.operation === "insert" &&
    isEventStreamEnvelope(row.value)
  )
}

